// ─── PARSE INCOMING TWILIO WHATSAPP MESSAGE ───────────────────────────────
// Twilio sends form-urlencoded data, N8N decodes it into $json
const body = $json.body || $json.Body || '';
const from = ($json.From || $json.from || '').replace('whatsapp:', '').trim();
const profileName = $json.ProfileName || $json.profileName || 'Usuario';

if (!from) throw new Error('No se pudo obtener el número de teléfono del remitente.');

return [{
  json: {
    phone: from,
    message: body.trim().toLowerCase(),
    messageRaw: body.trim(),
    profileName: profileName
  }
}];

// ─── STATE MACHINE MANAGER ─────────────────────────────────────────────────
// Uses N8N workflow static data to persist state per phone number.
// staticData is a key-value store that survives between executions.

const phone = $json.phone;
const message = $json.message;
const messageRaw = $json.messageRaw;
const profileName = $json.profileName;

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};

// Initialize conversation if new
if (!staticData.conversations[phone]) {
  staticData.conversations[phone] = { state: 'INICIO', data: {} };
}

const conv = staticData.conversations[phone];

// Keywords that restart the conversation
const RESTART_WORDS = ['hola', 'hi', 'hello', 'inicio', 'menu', 'menú', 'ticket', 'soporte', 'ayuda', 'help', 'start'];
if (RESTART_WORDS.includes(message)) {
  conv.state = 'INICIO';
  conv.data = {};
}

// ─── TYPE MAP ────────────────────────────────────────────────────────────────
const TIPO_MAP = {
  '1': 'Laptop', 'laptop': 'Laptop',
  '2': 'Desktop', 'desktop': 'Desktop', 'pc': 'Desktop',
  '3': 'Impresora', 'impresora': 'Impresora', 'printer': 'Impresora',
  '4': 'Red', 'red': 'Red', 'router': 'Red', 'switch': 'Red', 'wifi': 'Red',
  '5': 'Otro', 'otro': 'Otro', 'otros': 'Otro', 'other': 'Otro'
};

// ─── PRIORITY MAP ────────────────────────────────────────────────────────────
const PRIORITY_MAP = {
  '1': 'low', 'baja': 'low', 'bajo': 'low',
  '2': 'medium', 'media': 'medium', 'medio': 'medium', 'normal': 'medium',
  '3': 'high', 'alta': 'high', 'alto': 'high', 'urgente': 'high', 'urgent': 'high'
};

let action = '';
let responseMessage = '';
let ticketData = null;

// ─── STATE TRANSITIONS ──────────────────────────────────────────────────────
switch (conv.state) {
  case 'INICIO':
    conv.state = 'WAIT_TIPO';
    action = 'SEND_MESSAGE';
    responseMessage =
      `👋 Hola *${profileName}*! Soy el asistente de soporte de *ELSPEC ANDINA*.\n\n` +
      `📋 ¿Qué tipo de equipo necesitas reportar?\n\n` +
      `1️⃣ Laptop\n` +
      `2️⃣ Desktop / PC\n` +
      `3️⃣ Impresora\n` +
      `4️⃣ Red (Router / Switch)\n` +
      `5️⃣ Otro\n\n` +
      `_Responde con el número o el nombre del equipo._`;
    break;

  case 'WAIT_TIPO':
    const tipo = TIPO_MAP[message];
    if (!tipo) {
      action = 'SEND_MESSAGE';
      responseMessage =
        `❓ No reconocí esa opción. Por favor responde con:\n\n` +
        `1️⃣ Laptop  2️⃣ Desktop  3️⃣ Impresora  4️⃣ Red  5️⃣ Otro`;
      break;
    }
    conv.data.tipo = tipo;
    conv.state = 'WAIT_SERIAL';
    action = 'SEND_MESSAGE';
    responseMessage =
      `🖥️ *${tipo}* registrado.\n\n` +
      `🔍 ¿Cuál es el número de *serial* o *nombre* del equipo?\n` +
      `_(Si no lo sabes, escribe *no sé*)_`;
    break;

  case 'WAIT_SERIAL':
    conv.data.serial = messageRaw === 'no sé' || messageRaw === 'no se' || messageRaw === 'ns'
      ? 'No especificado'
      : messageRaw;
    conv.state = 'WAIT_DESC';
    action = 'SEND_MESSAGE';
    responseMessage =
      `📝 Perfecto. Ahora *describe el problema* con el equipo:\n\n` +
      `_Ej: No enciende, pantalla negra, hace ruido extraño..._`;
    break;

  case 'WAIT_DESC':
    if (messageRaw.length < 5) {
      action = 'SEND_MESSAGE';
      responseMessage = `⚠️ Por favor escribe una descripción más detallada del problema.`;
      break;
    }
    conv.data.descripcion = messageRaw;
    conv.state = 'WAIT_PRIORITY';
    action = 'SEND_MESSAGE';
    responseMessage =
      `🚦 ¿Qué tan *urgente* es el problema?\n\n` +
      `1️⃣ *Baja* — Puede esperar un par de días\n` +
      `2️⃣ *Media* — Afecta el trabajo pero hay solución temporal\n` +
      `3️⃣ *Alta* — Está bloqueando completamente el trabajo`;
    break;

  case 'WAIT_PRIORITY':
    const priority = PRIORITY_MAP[message];
    if (!priority) {
      action = 'SEND_MESSAGE';
      responseMessage =
        `❓ Opción no reconocida. Responde *1* (Baja), *2* (Media) o *3* (Alta).`;
      break;
    }
    conv.data.priority = priority;

    // ✅ All data collected — Create the ticket
    action = 'CREATE_TICKET';
    const now = new Date().toISOString();
    ticketData = {
      title: `[WhatsApp] Daño en equipo: ${conv.data.tipo} — ${conv.data.serial}`,
      description: `Reporte via WhatsApp de ${profileName} (+${phone.replace('+', '')}):\n\n${conv.data.descripcion}`,
      type: 'soporte',
      priority: conv.data.priority,
      author: 'WhatsApp Bot',
      status: 'open',
      deleted: false,
      assignedTo: [],
      assetId: null,
      whatsappPhone: phone,
      whatsappName: profileName,
      equipoTipo: conv.data.tipo,
      equipoSerial: conv.data.serial,
      createdAt: now
    };

    // Clear conversation state after ticket creation
    delete staticData.conversations[phone];
    break;

  default:
    conv.state = 'INICIO';
    action = 'SEND_MESSAGE';
    responseMessage = `Escribe *hola* para iniciar un nuevo reporte de soporte. 👋`;
    break;
}

return [{
  json: {
    phone,
    profileName,
    action,
    responseMessage: responseMessage || '',
    ticketData: ticketData || null
  }
}];

// Extract the Firestore document ID from the response
const firestoreResponse = $input.first().json;
const docName = firestoreResponse.name || '';
// name format: projects/{project}/databases/{db}/documents/tickets/{ID}
const docId = docName.split('/').pop() || 'NUEVO';
const shortId = docId.slice(-6).toUpperCase();

// The ticket data comes through from previous node via the input chain
// We need to get the phone from the response — fetch from firestoreResponse fields
const phone = firestoreResponse.fields?.whatsappPhone?.stringValue || '';

return [{
  json: {
    phone,
    shortId,
    responseMessage:
      `✅ *¡Ticket creado exitosamente!*\n\n` +
      `🎫 Número de caso: *#${shortId}*\n\n` +
      `El equipo de soporte técnico de ELSPEC ANDINA revisará tu solicitud pronto.\n` +
      `Si necesitas reportar otro problema, escribe *hola* nuevamente. 😊`
  }
}];
